package com.xda.sa2ration.automation;
import java.util.ArrayList;import java.util.Comparator;import java.util.List;
public final class AutomationEngine {
    public AutomationRule select(List<AutomationRule> rules,AutomationContext context){List<AutomationRule>sorted=new ArrayList<>(rules);sorted.sort(Comparator.comparingInt((AutomationRule r)->r.priority).reversed());for(AutomationRule r:sorted)if(r.enabled&&matches(r,context))return r;return null;}
    public boolean matches(AutomationRule r,AutomationContext c){try{switch(r.conditionType){case APPLICATION:return r.operand.equals(c.foregroundPackage);case CHARGING:return Boolean.parseBoolean(r.operand)==c.charging;case POWER_SAVER:return Boolean.parseBoolean(r.operand)==c.powerSaver;case HDR:return Boolean.parseBoolean(r.operand)==c.hdr;case GAME:return Boolean.parseBoolean(r.operand)==c.game;case VIDEO:return Boolean.parseBoolean(r.operand)==c.video;case EXTERNAL_DISPLAY:return Boolean.parseBoolean(r.operand)==c.externalDisplay;case DAY_OF_WEEK:return Integer.parseInt(r.operand)==c.dayOfWeek;case BATTERY_LEVEL:return c.batteryPercent<=Integer.parseInt(r.operand);case AMBIENT_LIGHT:return c.ambientLux<=Double.parseDouble(r.operand);case CURRENT_BRIGHTNESS:return c.brightness<=Integer.parseInt(r.operand);case TIME_RANGE:String[]parts=r.operand.split("-");int now=c.hour*60+c.minute;return now>=minutes(parts[0])&&now<=minutes(parts[1]);default:return false;}}catch(Exception ignored){return false;}}
    private int minutes(String value){String[]p=value.trim().split(":");return Integer.parseInt(p[0])*60+Integer.parseInt(p[1]);}
}
